import{_ as t,c as r,o as a,aj as l}from"./chunks/framework.Drljber8.js";const h=JSON.parse('{"title":"2.3 PET/US：衰减校正与降噪","description":"以 PET 的衰减校正为主线，补充超声常见噪声/伪像与基础降噪思路","frontmatter":{"title":"2.3 PET/US：衰减校正与降噪","description":"以 PET 的衰减校正为主线，补充超声常见噪声/伪像与基础降噪思路"},"headers":[],"relativePath":"guide/ch02/03-pet-us-preprocessing.md","filePath":"zh/guide/ch02/03-pet-us-preprocessing.md"}'),i={name:"guide/ch02/03-pet-us-preprocessing.md"};function o(s,e,n,p,c,d){return a(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="_2-3-pet-us-衰减校正与降噪" tabindex="-1">2.3 PET/US：衰减校正与降噪 <a class="header-anchor" href="#_2-3-pet-us-衰减校正与降噪" aria-label="Permalink to “2.3 PET/US：衰减校正与降噪”">​</a></h1><p>本节作为“重建前处理”的补充：用 <strong>PET 的衰减校正（attenuation correction）</strong> 串起功能成像的定量逻辑，同时概览 <strong>超声的噪声/伪像与降噪</strong>。</p><blockquote><p>说明：这里先把“为什么要做、做什么、怎么评估”讲清楚；工程实现与更深入推导会在后续迭代补全。</p></blockquote><hr><h2 id="_2-3-1-pet-为什么必须做衰减校正" tabindex="-1">2.3.1 PET：为什么必须做衰减校正？ <a class="header-anchor" href="#_2-3-1-pet-为什么必须做衰减校正" aria-label="Permalink to “2.3.1 PET：为什么必须做衰减校正？”">​</a></h2><p>PET 的 γ 光子在体内传播会被组织吸收/散射，导致探测到的符合事件减少：</p><ul><li><strong>不校正</strong>：深部结构会“偏暗”，SUV 等定量指标会系统性偏低</li><li><strong>校正后</strong>：不同体位/不同个体之间可比性更强，也更利于纵向随访</li></ul><p>常见策略：</p><ul><li><strong>PET-CT</strong>：用 CT 生成 μ-map（线性衰减系数图），并进行能量映射/尺度变换</li><li><strong>PET-MRI</strong>：通过分割/atlas/UTE 等方式估计 μ-map（更具挑战）</li></ul><h2 id="_2-3-2-pet-衰减校正与重建的关系" tabindex="-1">2.3.2 PET：衰减校正与重建的关系 <a class="header-anchor" href="#_2-3-2-pet-衰减校正与重建的关系" aria-label="Permalink to “2.3.2 PET：衰减校正与重建的关系”">​</a></h2><p>工程上通常把它看成重建管线中的一个“必要输入”：</p><ul><li>输入：投影/符合计数（sinogram / list-mode）、系统矩阵、μ-map（或其等价表示）</li><li>输出：校正后的定量图像（SUV、动态参数等）</li></ul><p>同时别忘了：衰减校正只是定量的一部分，常见还包括散射校正、随机符合校正、死时间校正、归一化等。</p><hr><h2 id="_2-3-3-超声-噪声与伪像-为什么看起来-糙" tabindex="-1">2.3.3 超声：噪声与伪像（为什么看起来“糙”） <a class="header-anchor" href="#_2-3-3-超声-噪声与伪像-为什么看起来-糙" aria-label="Permalink to “2.3.3 超声：噪声与伪像（为什么看起来“糙”）”">​</a></h2><p>超声图像常见现象：</p><ul><li><strong>散斑噪声（speckle）</strong>：相干成像导致的颗粒感</li><li><strong>阴影/增强</strong>：强反射或低衰减区域引起的能量分布变化</li><li><strong>混响（reverberation）</strong>：多次反射导致的条纹</li><li><strong>折射/旁瓣</strong>：几何与波束特性带来的伪像</li></ul><p>这些会影响：边界定位、分割稳定性、以及下游定量测量（例如血流谱参数）。</p><h2 id="_2-3-4-超声-降噪的基本思路" tabindex="-1">2.3.4 超声：降噪的基本思路 <a class="header-anchor" href="#_2-3-4-超声-降噪的基本思路" aria-label="Permalink to “2.3.4 超声：降噪的基本思路”">​</a></h2><ul><li><strong>传统滤波</strong>：中值、各向异性扩散、双边滤波等（在保边与平滑之间权衡）</li><li><strong>模型/学习方法</strong>：自监督去噪、扩散模型、针对 speckle 的特定损失与增强策略</li></ul><blockquote><p>在第5章（深度学习后处理）会结合具体任务（分割/分类）讨论“降噪是否真的有益”，以及如何避免“把病灶也抹掉”。</p></blockquote><hr><h2 id="_2-3-5-推荐阅读与下一步" tabindex="-1">2.3.5 推荐阅读与下一步 <a class="header-anchor" href="#_2-3-5-推荐阅读与下一步" aria-label="Permalink to “2.3.5 推荐阅读与下一步”">​</a></h2><ul><li><strong>PET 物理与定量</strong>：先把“衰减→定量偏差→校正”这条因果链吃透</li><li><strong>第1章模态回顾</strong>： <ul><li>PET/SPECT：<code>/guide/ch01/01-modalities/05-pet</code></li><li>超声：<code>/guide/ch01/01-modalities/04-ultrasound</code></li></ul></li><li><strong>第4章实战</strong>：后续会在 case study 里把一个“带指标评估”的小流程跑通（PSNR/SSIM 见 <code>4.4</code>）</li></ul>',24)])])}const u=t(i,[["render",o]]);export{h as __pageData,u as default};
